import React, { useState } from "react";
import MainPage from "./components/MainPage";
import LoginPage from "./components/LoginPageTemp";
import RegistryPageTemp from "./components/RegistryPageTemp"; 
import axios from 'axios';
import './App.css';
import ForgotPassword from "./components/ForgotPassword";

function App() {
  const [view, setView] = useState('scanner'); 
  const [file, setFile] = useState(null);
  const [result, setResult] = useState("");
  const [loading, setLoading] = useState(false);


  const handleUpload = async () => {
    if (!file) return alert("Proszę wybrać zdjęcie!");
    setLoading(true);
    setResult("");

    const formData = new FormData();
    formData.append('file', file);

    try {

      const response = await axios.post('http://localhost:8081/api/scan', formData);
      setResult(response.data);
    } catch (error) {
      setResult("Błąd połączenia z serwerem: " + error.message);
    } finally {
      setLoading(false);
    }
  };




  if (view === 'main') {
    return (
      <MainPage 
        onLogin={() => setView('login')}
        onRegistry={() => setView('registry')} 
      />
    );
  }


  if (view === 'login') {
    return (
      <LoginPage
        onBack={() => setView('main')}
        onRegistry={() => setView('registry')} 
        onLoginSuccess={() => setView('scanner')} 
        onForgotPassword={() => setView('forgot')}
      />
    );
  }


  if (view === 'registry') {
    return (
      <RegistryPageTemp
        onBack={() => setView('main')}
        onLogin={() => setView('login')} 
      />
    );
  }
if (view === 'forgot') {
    return (
      <ForgotPassword 
        onBack={() => setView('login')} 
      />
    );
  }

  return (
  <div className="dashboard-wrapper">

    <nav className="top-navbar">
      <div className="nav-logo">MoleCheckerAI</div>
      <div className="nav-actions">
        <button className="nav-button" onClick={() => alert("Opcje profilu")}>
          ⚙ Opcje
        </button>
        <button className="nav-button logout-btn" onClick={() => setView('main')}>
          Wyloguj się
        </button>
      </div>
    </nav>

    <div className="dashboard-container">

      <aside className="sidebar">
        <h2 className="sidebar-title">Historia Skanów</h2>
        <div className="history-list">
          <div className="history-item">
            <strong>2026-04-09</strong>
            <p>Wynik: Znamię łagodne</p>
          </div>
          <div className="history-item">
            <strong>2026-04-05</strong>
            <p>Wynik: Podejrzana zmiana</p>
          </div>
        </div>
      </aside>


      <main className="main-content">
        <div className="scanner-card">
          <h2 style={{color: 'white', marginBottom: '20px'}}>Nowe Badanie</h2>
          <p className="scanner-instruction">Prześlij zdjęcie fragmentu skóry do analizy</p>

          <div className="file-upload-wrapper">
            <input 
              type="file" 
              id="file-input" 
              onChange={(e) => setFile(e.target.files[0])} 
            />
          </div>

          <button className="analyze-button" onClick={handleUpload} disabled={loading}>
            {loading ? "Analizowanie..." : "Rozpocznij Skan"}
          </button>

          {result && (
            <div className="result-display">
              <h3 style={{color: 'white'}}>Wynik:</h3>
              <p className="diagnosis-text">{result}</p>
            </div>
          )}
        </div>
      </main>
    </div>
  </div>
);
}
export default App;
